const outputString = $input.item.json.output;
let cleaned = outputString.trim();

// Remove markdown code fences se existirem
cleaned = cleaned.replace(/^```json\s*/i, '').replace(/\s*```$/i, '');

// Remove marcador <<FIM>> se existir
cleaned = cleaned.replace(/<<FIM>>/g, '');

// Encontra o primeiro JSON completo contando chaves { }
let depth = 0, start = -1, end = -1;
for (let i = 0; i < cleaned.length; i++) {
  if (cleaned[i] === '{') {
    if (depth === 0) start = i;
    depth++;
  } else if (cleaned[i] === '}') {
    depth--;
    if (depth === 0) { end = i + 1; break; }
  }
}

const jsonString = cleaned.substring(start, end);
const data = JSON.parse(jsonString);

return [{
  json: {
    message: data.message,
    etapa: data.etapa,
    tipo_servico: data.tipo_servico || null,
    dados_coletados: data.dados_coletados,
    pronto_para_cotacao: data.pronto_para_cotacao,
    cotacao_multipla: data.cotacao_multipla || false,
    dados_multiplos: data.dados_multiplos || null,
    handoff: data.handoff,
    confidence: data.confidence,
    reason: data.reason,
    notify_text: data.notify_text || null
  }
}];

// Para n8n - Code Node
function cleanWebhookData(items) {
    const results = [];

    for (let i = 0; i < items.length; i++) {
        try {
            const item = items[i];

            // Se o item já tem a estrutura do n8n (com json property)
            const webhookData = item.json || item;

            // Se o body está em uma propriedade específica ou é o próprio objeto
            let bodyData;
            if (webhookData.body && typeof webhookData.body === 'string') {
                bodyData = JSON.parse(webhookData.body);
            } else if (webhookData.body && typeof webhookData.body === 'object') {
                bodyData = webhookData.body;
            } else {
                // Se não há body, usa o objeto inteiro
                bodyData = webhookData;
            }

            // Cria o objeto limpo
            const cleanedItem = {
                id: i + 1,
                webhookUrl: webhookData.webhookUrl || null,
                executionMode: webhookData.executionMode || null,
                event: bodyData.event || null,
                timestamp: bodyData.timestamp || null,
                ...bodyData // Espalha todas as propriedades do body
            };

            // Remove propriedades duplicadas se existirem
            delete cleanedItem.body;

            // Adiciona no formato do n8n
            results.push({ json: cleanedItem });

        } catch (error) {
            console.error(`Erro ao processar item ${i}:`, error);
            results.push({ 
                json: {
                    id: i + 1,
                    error: 'Erro ao processar dados',
                    errorMessage: error.message,
                    originalItem: items[i]
                }
            });
        }
    }

    return results;
}

