      resultado.push({ ap_num: ap.ap_num, dados_api: dados, opcao: null });
      continue;
    }

    // Tenta encontrar uma opção ainda não usada
    let opcaoEscolhida = null;
    for (const opcao of dados.opcoes) {
      if (!usados.has(opcao.apartamento)) {
        opcaoEscolhida = opcao;
        usados.add(opcao.apartamento);
        break;
      }
    }

    // Se todas já foram usadas, pega a primeira disponível diferente por índice
    if (!opcaoEscolhida) {
      opcaoEscolhida = dados.opcoes[Math.min(ap.ap_num - 1, dados.opcoes.length - 1)];
    }

    resultado.push({ ap_num: ap.ap_num, dados_api: dados, opcao: opcaoEscolhida });
  }

  return resultado;
